mapper.select:
select ri.release_issue_id, ri.release_plan_id, ri.issue_id, ri.task_id, ri.category, ri.notes,
       ri.added_by, ri.added_at, ri.deleted,
       rp.name as release_name, su.user_name as added_by_name
from release_issue ri
left join release_plan rp on ri.release_plan_id = rp.release_plan_id and rp.deleted = 0
left join sys_user su on ri.added_by = su.user_id and su.del_flag = '0'
where ri.deleted = 0
and ri.release_plan_id = #{releasePlanId}
and ri.issue_id = #{issueId}
and ri.task_id = #{taskId}
and ri.category = #{category}
order by ri.added_at desc
